test_cases.assertion_pseudocode:
// Use static analysis or code inspection to confirm absence of os.Exit/log.Fatal in store code
// Runtime: use a read-only db to force error
ws, err = store.CreateWorkspace({slug: 'any-ws', git_url: 'https://github.com/org/repo.git', owner_id: 'user-uuid-1'})
assert ws == nil
assert err != nil
// Process is still running after this call

// Static check: search source files
matches = grep_source_files('cmd/', 'os.Exit')
assert len(matches) == 0
// Also verify log.Fatal is absent in workspace handler files
matches2 = grep_source_files('cmd/', 'log.Fatal')
assert len(matches2) == 0

// Search for old organizational usage patterns
files = find_files(['architecture/', 'docs/'], '*.md')
for file in files:
    content = read_file(file)
    // Check that 'workspace' is not used in contexts describing organizational containers or groups
    organizational_workspace_refs = find_pattern(content, r'workspace[s]? (is|are|represents?) (a group|an organizational|a container)')
    assert len(organizational_workspace_refs) == 0, f'{file} still has organizational workspace references'

